<?php
namespace app\Repositories; class MemberRepository extends BaseRepository{ public function all(string $q=''):array{return $q?$this->fetchAll("SELECT * FROM members WHERE member_code LIKE ? OR full_name LIKE ? OR phone LIKE ? OR identity_number LIKE ? OR student_code LIKE ? OR class_name LIKE ? OR major LIKE ? ORDER BY id DESC",["%$q%","%$q%","%$q%","%$q%","%$q%","%$q%","%$q%"]):$this->fetchAll("SELECT * FROM members ORDER BY id DESC");} public function find(int $id):?array{return $this->fetch("SELECT * FROM members WHERE id=?",[$id]);} public function create(array $d):int{$this->execute("INSERT INTO members(member_code,full_name,student_code,class_name,major,phone,email,identity_number,address,status) VALUES(?,?,?,?,?,?,?,?,?,?)",[$d['member_code'],$d['full_name'],$d['student_code']??null,$d['class_name']??null,$d['major']??null,$d['phone']??null,$d['email']??null,$d['identity_number']??null,$d['address']??null,$d['status']??'active']);return $this->lastInsertId();} public function update(int $id,array $d):bool{return $this->execute("UPDATE members SET member_code=?,full_name=?,student_code=?,class_name=?,major=?,phone=?,email=?,identity_number=?,address=?,status=? WHERE id=?",[$d['member_code'],$d['full_name'],$d['student_code']??null,$d['class_name']??null,$d['major']??null,$d['phone']??null,$d['email']??null,$d['identity_number']??null,$d['address']??null,$d['status']??'active',$id]);} public function delete(int $id):bool{return $this->execute("DELETE FROM members WHERE id=?",[$id]);} public function unreturnedCount(int $id):int{return (int)$this->fetch("SELECT COUNT(*) c FROM borrows WHERE member_id=? AND status='borrowing'",[$id])['c'];}}
